		function SendToServer()
{       
	GetProxy().StoreService().SetUserStore("Lista_IDS_IC", array2stringcustom(arrB, "ROWS", "ROW"));
	return true;
}

function Filtrar() {

 	if(Ctrl("list2").TotalRowsCount()<=0){
		CtrlEnabled("btnAccept",false);
	  alert("Debe seleccionar al menos un legajo para continuar.");
		return false;
	} 
		SendToServer();
		Ctrl("rpt").SetXValue("0");
		Ctrl("main").DoEvent("ACCEPT");	
}

function FiltrarRpt()
{
	SendToServer();
	Ctrl("rpt").SetXValue("1");
	Ctrl("main").DoEvent("ACCEPT");	
}

function enable_custom_buttons()
{  
	if(Ctrl("list2").TotalRowsCount()>0){
		CtrlEnabled("btnAccept",true); 
		CtrlEnabled("btnReporte",true); 

	}else{
	  CtrlEnabled("btnAccept",false);
	  CtrlEnabled("btnReporte",false);

	}
}         

function val_orden() 
{
if (Ctrl('orden1').GetXValue() == "P.c_ubicacion" || Ctrl('orden1').GetXValue() == "U.d_ubicacion")
 {
 	CtrlEnabled('orden2',true);
 }
else
 {
  CtrlEnabled('orden2',false);
  Ctrl("orden2").SetXValue("");
 } 
}                  


function set_tipo()
{
	if(Ctrl('tipo_liq').GetXValue() == '3')
	{
		//Ctrl("oi_liquidacionFil").SetWhere('LIQ19_LIQUIDACION.oi_liquidacion IN (SELECT VARLIQ.oi_liquidacion FROM LIQ19_VAL_VARGN AS VARLIQ, LIQ09_VARIABLES AS V JOIN VARLIQ.oi_variable INNER V.oi_variable WHERE V.c_variable = \'np_igotroagente\') OR LIQ19_LIQUIDACION.oi_liquidacion IN (SELECT LIQPER.oi_liquidacion FROM	LIQ25_VAL_VAREN AS VARPER, LIQ09_VARIABLES AS V,LIQ25_PERSONAL_LIQ AS LIQPER JOIN	VARPER.oi_variable INNER V.oi_variable,	LIQPER.oi_personal_liq INNER VARPER.oi_personal_liq	WHERE V.c_variable = \'np_igotroagente\') ');
		var np = new NomadProxy("", ut);
		var nSQL = np.SQLService();
		var qryVar = Ctrl("main").getResource("qry_buscar_variable");
		var resultVar = nSQL.Get(qryVar, "<PARAM />");
		var xmldocVar = new NomadXML(resultVar).FirstChild();
	    var n_valor = xmldocVar.GetAttr("n_valor");  

		Ctrl("oi_liquidacionFil").SetWhere('LIQ19_LIQUIDACION.oi_liquidacion in (SELECT E.oi_liquidacion FROM LIQ19_EJECUCIONES AS E, LIQ99_LIQUIDACION AS L, LIQ99_RECIBOS AS R, LIQ20_VAR_GR_CONC as GR where E.oi_liquidacion_ddo = L.oi_liquidacion_ddo and L.oi_liquidacion_ddo = R.oi_liquidacion_ddo and R.oi_tot_liq_per = GR.oi_tot_liq_per and L.c_estado = \'F\' AND GR.c_grupo = \'1\' AND GR.'+n_valor+' = \'1\' group by E.oi_liquidacion)');

		Ctrl("l_anioAnterior").SetXValue("0"); 			
	}		
	else if(Ctrl('tipo_liq').GetXValue() == '2' || Ctrl('tipo_liq').GetXValue() == '1.1')
	{ 
		Ctrl("oi_liquidacionFil").SetWhere("");
		Ctrl("l_anioAnterior").SetXValue("0");		
	}
	else if(Ctrl('tipo_liq').GetXValue() == '1' || Ctrl('tipo_liq').GetXValue() == '4')
	{
		Ctrl("oi_liquidacionFil").SetWhere("");
		Ctrl("l_anioAnterior").SetXValue("1");		
	}

	Ctrl("oi_liquidacionFil").SetXValue("");
}  

function setNombreArchivo() {       


	var nombre;
	var periodoMin;
	var np = new NomadProxy("", ut);
	var nSQL = np.SQLService();	
	var qry;	 
	var result;
	var xmldoc;

 	if(Ctrl("main").GetMode()=="F2122") {
 		//Es modo F2122
 		nombre = "F2122.";
 		periodoMin = 202400;
 	} else {
 		//Es modo FILTER (F1359)
 		nombre = "F1359.";
 		periodoMin = 201800;
 	}

	if(Ctrl("empresa").GetXValue()!='') {
		qry = Ctrl("main").getResource("qry_cuit");
		result = nSQL.Get(qry, "<PARAM empresa=\""+Ctrl("empresa").GetXValue()+"\"  />");
		xmldoc = new NomadXML(result);
	 	nombre += xmldoc.FirstChild().GetAttr("cuit").replace("-", "").replace("-", "")+".";				
	} else {
	   Ctrl("nombreArchivo").SetXValue("");
	   return;
	}

	if(Ctrl("oi_liquidacionFil").GetXValue()!='') {
		qry = Ctrl("main").getResource("qry_liq");
		result = nSQL.Get(qry, "<PARAM liquidacion=\""+Ctrl("oi_liquidacionFil").GetXValue()+"\"  />");
		xmldoc = new NomadXML(result);


		if(parseInt(Ctrl("tipo_liq").GetXValue())==1 || Ctrl("tipo_liq").GetXValue()=='1.1' || Ctrl("tipo_liq").GetXValue()=='4') {
		  if(parseInt(xmldoc.FirstChild().GetAttr("periodo")) < periodoMin) {
				alert("No se permite presentar liquidaciones anteriores al período " + periodoMin + ".");
				Ctrl("nombreArchivo").SetXValue("");
				Ctrl("oi_liquidacionFil").SetXValue("");
				return; 
			}
		}

		var periodo = xmldoc.FirstChild().GetAttr("periodo").substring(0, 4);
		if(Ctrl("tipo_liq").GetXValue()=='1' || Ctrl("tipo_liq").GetXValue()=='4') {
			periodo-=1; 
			periodo = periodo.toString();
		}
		Ctrl("f_liq_hasta").SetXValue(xmldoc.FirstChild().GetAttr("f_liq_hasta"));
		nombre += completarCerosFinal(periodo,8,'0')+".";

	} else {
	   Ctrl("nombreArchivo").SetXValue("");
	   return;
	}

	if(Ctrl("secuencia").GetXValue()!='') {
		nombre += completarCerosFinal(Ctrl("secuencia").GetXValue(),4,'0');		
	} else { 
		Ctrl("secuencia").SetXValue('0');
		nombre += completarCerosFinal(Ctrl("secuencia").GetXValue(),4,'0');
	}

	Ctrl("nombreArchivo").SetXValue(nombre + ".txt");  

}

function completarCerosFinal(cadena, longitud, caracter){
 var cadLong = longitud - cadena.length;
 for(i=0;i<cadLong;i++)
 {
 	cadena += caracter; 
 }
 return cadena;
}

function LoadForm()
{             
	enable_custom_buttons();
	Ctrl("vgroupDatosPers").SetXValue('0');
	if(Ctrl("secuencia").GetXValue()=='')	
		Ctrl("secuencia").SetXValue('0');      


	inter = Ctrl("interface");          
  	MyCUR = inter.m_opts.LastChild();
 	inter.SetXValue(MyCUR.GetAttr("value"));			 

}   

function exec_qry()
{
	var np, nSQL, i;

	np = new NomadProxy("", ut);
	nSQL = np.SQLService();

	var qry = Ctrl("main").getResource("qry_" + Ctrl("tab_filtro").GetSelectedPanelID());

	var qryMembers = qry.split("##");
	for (i=1; i<qryMembers.length; i+=2)
	{
		if (Ctrl(qryMembers[i]).m_Required && Ctrl(qryMembers[i]).GetXValue()=="")
		{
			alert("El valor es requerido");
			Ctrl(qryMembers[i]).SetFocus();
			return null;
		}				

		qryMembers[i]=EncodeXML(Ctrl(qryMembers[i]).GetXValue());
	}

  qry = qryMembers.join("");
  if (Ctrl("DEBUG")) Ctrl("DEBUG").SetXValue(qry);

  var result = nSQL.Get(qry, "");
 	var resultArray = string2array(result);
 	// Ejecuta query EXTERNO en caso del tipo 2

 	if(Ctrl('tipo_liq').GetXValue() == '2')
 	{
 	  qry = Ctrl("main").getResource("qry_externo2");
 		qryMembers = qry.split("##");
		for (i=1; i<qryMembers.length; i+=2)
		{
			qryMembers[i]=EncodeXML(Ctrl(qryMembers[i]).GetXValue());
		}
	  qry = qryMembers.join("");
	  if (Ctrl("DEBUG")) Ctrl("DEBUG").SetXValue(Ctrl("DEBUG").GetXValue() + "\n\nQuery Externo:\n" + qry);
	  result = nSQL.Get(qry, "<PARAM liquidacion=\""+Ctrl("oi_liquidacionFil").GetXValue()+"\" f_liq_hasta=\""+Ctrl("f_liq_hasta").GetXValue().substring(0,8)+"\"  />");
	  var auxResult = string2array(result);
	  intersect(resultArray, auxResult);
 	}
 	// Ejecuta query EXTERNO en caso del tipo 3
 	else if(Ctrl('tipo_liq').GetXValue() == '3')
 	{  		
 	  qry = Ctrl("main").getResource("qry_externo3");
 		qryMembers = qry.split("##");
		for (i=1; i<qryMembers.length; i+=2)
		{
			qryMembers[i]=EncodeXML(Ctrl(qryMembers[i]).GetXValue());
		}
	  qry = qryMembers.join("");
	  if (Ctrl("DEBUG")) Ctrl("DEBUG").SetXValue(Ctrl("DEBUG").GetXValue() + "\n\nQuery Externo:\n" + qry);
	  result = nSQL.Get(qry, "<PARAM liquidacion=\""+Ctrl("oi_liquidacionFil").GetXValue()+"\" f_liq_hasta=\""+Ctrl("f_liq_hasta").GetXValue().substring(0,8)+"\"  />");
	  var auxResult = string2array(result);
	  intersect(resultArray, auxResult);
 	} 	

	// Ejecuta query de ATRIBUTOS EXTERNOS
 	if (Ctrl("main").getResource("qry_externo_attr"))
 	{
 		qry = Ctrl("main").getResource("qry_externo_attr");
 		qryMembers = qry.split("##");
		for (i=1; i<qryMembers.length; i+=2)
		{
			qryMembers[i]=EncodeXML(Ctrl(qryMembers[i]).GetXValue());
		}
	  qry = qryMembers.join("");
	  if (Ctrl("DEBUG")) Ctrl("DEBUG").SetXValue(Ctrl("DEBUG").GetXValue() + "\n\nQuery de Atributos Externos:\n" + qry);
	  result = nSQL.Get(qry, array2string(resultArray));
	  resultArray = string2array(result);
	}

 	//Filtra por la variable solo si el formulario 2122
 	if(Ctrl("main").GetMode()=="F2122") {
 	  qry = Ctrl("main").getResource("qry_externo");
 		qryMembers = qry.split("##");
		for (i=1; i<qryMembers.length; i+=2)
		{
			qryMembers[i]=EncodeXML(Ctrl(qryMembers[i]).GetXValue());
		}
	  qry = qryMembers.join("");
	  if (Ctrl("DEBUG")) Ctrl("DEBUG").SetXValue(Ctrl("DEBUG").GetXValue() + "\n\nQuery Externo:\n" + qry);
	  result = nSQL.Get(qry, "");
	  var auxResult = string2array(result);
	  intersect(resultArray, auxResult);
 	}

  return resultArray;
}
